class Solution {
    public int bestClosingTime(String customers) {
        int n = customers.length();
        int[] prefixSum = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixSum[i + 1] = prefixSum[i] + (customers.charAt(i) == 'Y' ? 1 : 0);
        }
        int minPenalty = Integer.MAX_VALUE;
        int bestHour = -1;
        for (int i = 0; i <= n; i++) {
            int penalty = (prefixSum[n] - prefixSum[i]) + (i - prefixSum[i]);
            if (penalty < minPenalty) {
                minPenalty = penalty;
                bestHour = i;
            }
        }
        return bestHour;
    }
}
efficiency: HIGH
time complexity: O(N)
space complexity: O(N)
energy implications: LOW
explanation: The solution uses a prefix sum array to efficiently count the number of 'Y's up to each hour, then iterates through the hours to find the one with the minimum penalty, calculated as the sum of 'Y's after the hour and 'N's before the hour.
